#include <bits/stdc++.h>
using namespace std;

const int N=2e5+10;

struct Edge{
    int u;
    long long d;
    bool operator<(Edge x)const{
        if(d==x.d)
            return u>x.u;
        return d<x.d;
    }
}c[N];

int n,m,sz[N],u[N],t[N],fa[N],dep[N],f[N];
long long dis[N],len[N][20];
bool b[N];
vector<Edge> e[N];
set<Edge> s[N];

void dfs(int x,int fa,int dep){
    len[x][dep]=dis[x];
    sz[x]=1;
    for(Edge y:e[x])
        if(y.u!=fa && !b[y.u]){
            dis[y.u]=dis[x]+y.d;
            dfs(y.u,x,dep);
            sz[x]+=sz[y.u];
        }
}

int Bal(int x,int S){
    for(Edge y:e[x])
        if(sz[y.u]<sz[x] && sz[y.u]*2>S && !b[y.u])
            return Bal(y.u,S);
    return x;
}

void solve(int x,int lst){
    //printf("%d %d\n",x,lst);
    fa[x]=lst;
    dep[x]=dep[lst]+1;
    dis[x]=0;
    dfs(x,0,dep[x]);
    b[x]=1;
    for(Edge y:e[x])
        if(!b[y.u])
            solve(Bal(y.u,sz[y.u]),x);
}

int main(){
    scanf("%d",&n);
    for(int i=1,u,v,w;i<n;i++){
        scanf("%d%d%d",&u,&v,&w);
        e[u].push_back({v,w});
        e[v].push_back({u,w});
    }
    dis[1]=0;
    dfs(1,0,0);
    solve(Bal(1,sz[1]),0);
    scanf("%d",&m);
    for(int i=1;i<=m;i++)
        scanf("%d%d",&c[i].u,&c[i].d);
    sort(c+1,c+m+1);
    int ans=0;
    for(int i=1;i<=m;i++){
        f[i]=1;
        for(int j=c[i].u;j;j=fa[j]){
            if(s[j].empty())
                continue;
            auto it=s[j].upper_bound({0,c[i].d-len[c[i].u][dep[j]]});
            if(it==s[j].begin())
                continue;
            it--;
            f[i]=max(f[i],(*it).u+1);
        }
        for(int j=c[i].u;j;j=fa[j]){
            if(s[j].empty()){
                s[j].insert({f[i],c[i].d+len[c[i].u][dep[j]]});
                continue;
            }
            auto it=s[j].upper_bound({0,c[i].d+len[c[i].u][dep[j]]});
            if(it==s[j].begin())
                s[j].insert({f[i],c[i].d+len[c[i].u][dep[j]]});
            else{
                it--;
                if((*it).u<f[i])
                    s[j].insert({f[i],c[i].d+len[c[i].u][dep[j]]});
            }
            it=s[j].find({f[i],c[i].d+len[c[i].u][dep[j]]});
            if(it==s[j].end())
                continue;
            while(1){;
                auto itx=++it;
                it--;
                if(itx==s[j].end())
                    break;
                if((*itx).u<=(*it).u)
                    s[j].erase(itx);
                else
                    break;
            }
        }
        ans=max(ans,f[i]);
        //printf("%d ",f[i]);
    }
    printf("%d",ans);
    return 0;
}
